+function skipUsingDeclarationTrivia(parser: Parser, index: number): number {
+  const { source } = parser;
+  while (index < source.length) {
+    const char = source.charCodeAt(index);
+    if (char === 0x20 || char === 0x09 || char === 0x0b || char === 0x0c) {
+      index++;
